{
  "sql": "SELECT st.user_id, st.username, count(st.id) as total_sessions, sum(st.hits) as total_hits, sum(st.misses) as total_misses, round((sum(st.hits) * 100.0) / (sum(st.hits) + sum(st.misses)), 2) as avg_accuracy, max(st.max_combo) as peak_combo, sum(st.xp_earned) as weekly_xp_gained, up.current_level, up.total_xp FROM scores_telemetry st JOIN user_progression up ON st.user_id = up.user_id WHERE st.created_at >= datetime('now', '-7 days') AND st.integrity_flag = 'HIGH_INTEGRITY' GROUP BY st.user_id, st.username, up.current_level, up.total_xp ORDER BY weekly_xp_gained DESC LIMIT 10;"
}

