const d1Result = $input.first().json;
// Cloudflare D1 v4 REST API returns result array
const players = d1Result.result?.[0]?.results || d1Result.result?.results || [];

if (players.length === 0) {
  return {
    markdownReport: "### 📊 AimSync Weekly Performance Digest\n\nNo active training telemetry recorded this week.",
    htmlReport: "<h3>📊 AimSync Weekly Performance Digest</h3><p>No active training telemetry recorded this week.</p>"
  };
}

let markdown = "### 📊 AimSync Weekly Performance Summary\n\nHere are the top-performing active users on the AimSync network over the past 7 days:\n\n";
markdown += "| Rank | Username | Level | Sessions | Total Hits | Avg Accuracy | Peak Combo | Weekly XP |\n";
markdown += "| :--- | :--- | :--- | :--- | :--- | :--- | :--- | :--- |\n";

let html = `
<h3>📊 AimSync Weekly Performance Summary</h3>
<p>Here are the top-performing active users on the AimSync network over the past 7 days:</p>
<table border="1" cellpadding="5" style="border-collapse: collapse; font-family: sans-serif; width: 100%; max-width: 600px;">
  <thead>
    <tr style="background-color: #f2f2f2; text-align: left;">
      <th>Rank</th>
      <th>Username</th>
      <th>Level</th>
      <th>Sessions</th>
      <th>Total Hits</th>
      <th>Avg Accuracy</th>
      <th>Peak Combo</th>
      <th>Weekly XP</th>
    </tr>
  </thead>
  <tbody>
`;

players.forEach((p, index) => {
  const rank = index + 1;
  markdown += `| ${rank} | **${p.username}** | ${p.current_level} | ${p.total_sessions} | ${p.total_hits.toLocaleString()} | ${p.avg_accuracy}% | ${p.peak_combo} | +${p.weekly_xp_gained.toLocaleString()} XP |\n`;

  html += `
    <tr>
      <td>${rank}</td>
      <td><strong>${p.username}</strong></td>
      <td>${p.current_level}</td>
      <td>${p.total_sessions}</td>
      <td>${p.total_hits.toLocaleString()}</td>
      <td>${p.avg_accuracy}%</td>
      <td>${p.peak_combo}</td>
      <td style="color: #2e7d32; font-weight: bold;">+${p.weekly_xp_gained.toLocaleString()} XP</td>
    </tr>
  `;
});

markdown += "\n\n*This automated diagnostics report is compiled directly from the Cloudflare D1 scores telemetry database. Low integrity runs have been excluded.*";
html += `
  </tbody>
</table>
<p style="font-size: 11px; color: #666; margin-top: 15px;"><em>This automated diagnostics report is compiled directly from the Cloudflare D1 scores telemetry database. Low integrity runs have been excluded.</em></p>
`;

return {
  markdownReport: markdown,
  htmlReport: html
};
